mapper.select:
SELECT gmd.id, gmd.academic_year, gmd.major_direction_id, md.direction_name, m.major_name, md.level, md.years, gmd.remarks, gmd.created_at, gmd.updated_at FROM grade_major_directions gmd LEFT JOIN major_directions md ON gmd.major_direction_id = md.id AND md.deleted = 0 LEFT JOIN majors m ON md.major_id = m.id AND m.deleted = 0 WHERE gmd.deleted = 0
AND gmd.academic_year = #{params.academicYear}
AND gmd.major_direction_id = #{params.majorDirectionId}
ORDER BY gmd.academic_year DESC, m.major_name, md.direction_name
